#nullable enable // autogenerated

using System;
using System.Linq;
using MVZ2.UI.Map;
using PVZEngine;
using TMPro;
using UnityEngine;

namespace MVZ2.Map
{
    public class MapModel : MonoBehaviour
    {
        #region 无尽轮数
        public void SetEndlessFlagsTextActive(bool active)
        {
            if (!endlessFlagsText)
                return;
            endlessFlagsText.gameObject.SetActive(active);
        }
        public void SetEndlessFlagsText(string text)
        {
            if (!endlessFlagsText)
                return;
            endlessFlagsText.text = text;
        }
        #endregion

        #region 无尽按钮
        public MapButton? GetEndlessMapButton()
        {
            return endlessButton;
        }
        public void SetEndlessButtonInteractable(bool interactable)
        {
            if (!endlessButton)
                return;
            endlessButton.interactable = interactable;
        }
        public void SetEndlessButtonColor(Color color)
        {
            if (!endlessButton)
                return;
            endlessButton.SetColor(color);
        }
        public void SetEndlessButtonText(string text)
        {
            if (!endlessButton)
                return;
            endlessButton.SetText(text);
        }
        #endregion

        #region 地图按钮
        public int GetMapButtonCount()
        {
            return mapButtons.Length;
        }
        public MapButton? GetMapButton(int index)
        {
            if (index < 0 || index >= mapButtons.Length)
                return null;
            return mapButtons[index];
        }
        public void SetMapButtonInteractable(int index, bool interactable)
        {
            var button = GetMapButton(index);
            if (!button.Exists())
                return;
            button.interactable = interactable;
        }
        public void SetMapButtonColor(int index, Color color)
        {
            var button = GetMapButton(index);
            if (!button.Exists())
                return;
            button.SetColor(color);
        }
        public void SetMapButtonText(int index, string text)
        {
            var button = GetMapButton(index);
            if (!button.Exists())
                return;
            button.SetText(text);
        }
        public void SetMapButtonBorder(int index, Sprite? back, Sprite? bottom, Sprite? overlay)
        {
            var button = GetMapButton(index);
            if (!button.Exists())
                return;
            button.SetBorderSprite(back, bottom, overlay);
        }
        public void SetMapButtonBorderToDefault(int index)
        {
            var button = GetMapButton(index);
            if (!button.Exists())
                return;
            button.SetBorderSpriteToDefault();
        }
        #endregion


        #region 地图元素
        public MapElement? GetMapElement(NamespaceID id)
        {
            return mapElements.FirstOrDefault(e => e.definitionID?.Get() == id);
        }
        public MapElement[] GetMapElements()
        {
            return mapElements;
        }
        #endregion
        private void Awake()
        {
            foreach (var button in mapButtons)
            {
                var index = Array.IndexOf(mapButtons, button);
                button.OnClick += () => OnMapButtonClick?.Invoke(index);
            }
            if (endlessButton)
            {
                endlessButton.OnClick += () => OnEndlessButtonClick?.Invoke();
            }
            mapElements = elementRoot.GetComponentsInChildren<MapElement>();
        }
        public event Action<int>? OnMapButtonClick;
        public event Action? OnEndlessButtonClick;
        [SerializeField]
        private TextMeshPro endlessFlagsText = null!;
        [SerializeField]
        private Transform elementRoot = null!;
        [SerializeField]
        private MapButton endlessButton = null!;
        [SerializeField]
        private MapButton[] mapButtons = null!;
        private MapElement[] mapElements = null!;
    }
}
